/**
 * @summary Get applications for the current user (student or employer view)
 */
export const getGetApplicationsUrl = (params?: GetApplicationsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/applications?${stringifiedParams}`
    : `/api/applications`;
};

export const getApplications = async (
  params?: GetApplicationsParams,
  options?: RequestInit,
): Promise<Application[]> => {
  return customFetch<Application[]>(getGetApplicationsUrl(params), {
    ...options,
    method: "GET",
  });
};

